    /// <param name="condition">A WQL WHERE condition (e.g. <c>"Name='C:'"</c>).</param>
    internal static IEnumerable<OperatingSystem> GetInstances(WmiConnection connection, string condition)
    {
        var query = new WmiQuery(connection, $"SELECT * FROM {WmiClassName} WHERE {condition}");
        using var enumerator = query.GetEnumerator();
